    status = 'Unknown'
    for doc_project, doc_status in status_map.items():
        if base_name in doc_project or doc_project in base_name:
            status = doc_status
            break

    results.append({
        'Project_Name': project_name,
        'Funding_Source': rec['Funding_Source'],
        'Amount': int(rec['Amount']),
        'Status': status
    })

